import { InputField } from "@/components/Form/InputField";
import SelectField from "@/components/Form/SelectField";
import AdminLayout from "@/components/Layout/AdminLayout";
import { apiBaseUrl } from "@/config";
import { useCustomSWR } from "@/hooks/useCustomSWR";
import { OriginAddress } from "@/types";
import axios from "axios";
import React, { FormEvent, useEffect, useState } from "react";

type TProvince = {
  province_id: string;
  province: string;
};

type TCity = {
  city_id: string;
  province_id: string;
  province: string;
  type: string;
  city_name: string;
  postal_code: string;
};

const AddAddress = () => {
  const [originAddressData, setOriginAddressData] = useState<OriginAddress>({
    addressName: "",
    city: "",
    cityId: "",
    province: "",
    provinceId: "",
    street: "",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  });
  const [provinceOptions, setProvinceOptions] = useState<string[]>([]);
  const [cityOptions, setCityOptions] = useState<string[]>([]);
  // const [selectedProvince, setSelectedProvince] = useState<TProvince>();
  // const [selectedCity, setSelectedCity] = useState<TCity>();
  const province = useCustomSWR("/api/getProvince");
  const city = useCustomSWR(
    `/api/getCity?province=${originAddressData.provinceId}`
  );

  const fetchOriginAddress = async() => {
    const response = await axios.post(`${apiBaseUrl}`)
  }

  const handleOnChange = (
    e: React.ChangeEvent<HTMLSelectElement | HTMLInputElement>
  ) => {
    if (e.target.name === "province") {
      if (province.data) {
        const selectProvince = province.data.rajaongkir.results.find(
          (value: TProvince) => {
            return value.province === e.target.value;
          }
        );
        setOriginAddressData((prevData) => {
          return {
            ...prevData,
            [e.target.name]: selectProvince.province,
            provinceId: selectProvince.province_id,
          };
        });
      }
    } else if (e.target.name === "city") {
      if (city.data.rajaongkir.results.length != 0) {
        const selectCity = city.data.rajaongkir.results.find((value: TCity) => {
          return value.city_name === e.target.value;
        });
        setOriginAddressData((prevData) => {
          return {
            ...prevData,
            [e.target.name]: selectCity.city_name,
            provinceId: selectCity.city_id,
          };
        });
      }
    } else {
      setOriginAddressData((prevData) => {
        return {
          ...prevData,
          [e.target.name]: e.target.value,
        };
      });
    }
  };

  const onSubmitForm = (e: FormEvent) => {
    e.preventDefault();
  };

  // const handleOnChangeProvince = (e: React.ChangeEvent<HTMLSelectElement>) => {
  //   if (province.data) {
  //     const selectProvince = province.data.rajaongkir.results.find(
  //       (value: TProvince) => {
  //         return value.province === e.target.value;
  //       }
  //     );
  //     setSelectedProvince(selectProvince);
  //     selectedProvince;
  //   }
  // };

  // const handleOnChangeCity = (e: React.ChangeEvent<HTMLSelectElement>) => {
  //   if (city.data) {
  //     const selectCity = city.data.rajaongkir.results.find((value: TCity) => {
  //       return value.city_name === e.target.value;
  //     });
  //     setSelectedCity(selectCity);
  //   }
  // };

  useEffect(() => {
    if (originAddressData.provinceId) {
      city.mutate();
    }
  }, [originAddressData.provinceId, city]);

  useEffect(() => {
    if (province.data) {
      const provName = province.data.rajaongkir.results.map(
        (value: TProvince) => value.province
      );

      setProvinceOptions(provName);
    }
  }, [province.data]);

  useEffect(() => {
    if (city.data) {
      const cityName = city.data.rajaongkir.results.map(
        (value: TCity) => value.city_name
      );

      setCityOptions(cityName);
    }
  }, [city.data]);

  return (
    <AdminLayout>
      <h1 className="uppercase font-semibold text-2xl text-black pt-14">
        Add New Address
      </h1>
      <form className="mt-5" onSubmit={onSubmitForm}>
        <InputField
          type="text"
          name="addressName"
          value={""}
          onChange={() => {}}
          label="Address Name"
          placeholder="ex: JNE Kuningan"
        />
        <InputField
          type="text"
          name="street"
          value={""}
          onChange={() => {}}
          label="Street"
          placeholder="ex: Jl. Ini nama Jalan No. 20, Kuningan, Setiabudi"
        />
        <div className="flex gap-4">
          <SelectField
            id="province"
            name="province"
            onChange={handleOnChange}
            options={provinceOptions}
            label="Province"
            defaultValue={
              originAddressData.province ? originAddressData.province : ""
            }
          />
          <SelectField
            id="city"
            name="city"
            onChange={handleOnChange}
            options={cityOptions}
            label="City"
            defaultValue={originAddressData.city ? originAddressData.city : ""}
          />
        </div>
      </form>
    </AdminLayout>
  );
};

export default AddAddress;
